"""
This module contains the Board class to manage the checkers board.
"""

class PiecePosition:
    def __init__(self, row, col):
        self.row = row
        self.col = col

class Piece:
    def __init__(self, color, is_king=False):
        self.color = color
        self.is_king = is_king

    def __str__(self):
        return 'K' if self.is_king else self.color[0]

class Board:
    def __init__(self):
        self.board = [[None for _ in range(8)] for _ in range(8)]
        self.initialize_board()

    def initialize_board(self):
        for i in range(3):
            for j in range((i + 1) % 2, 8, 2):
                self.board[i][j] = Piece('black')
        for i in range(5, 8):
            for j in range((i + 1) % 2, 8, 2):
                self.board[i][j] = Piece('red')

    def move_piece(self, from_pos: PiecePosition, to_pos: PiecePosition):
        piece = self.board[from_pos.row][from_pos.col]
        if piece:
            self.board[to_pos.row][to_pos.col] = piece
            self.board[from_pos.row][from_pos.col] = None

    def capture_piece(self, from_pos: PiecePosition, to_pos: PiecePosition):
        middle_pos = PiecePosition((from_pos.row + to_pos.row) // 2, (from_pos.col + to_pos.col) // 2)
        if self.board[middle_pos.row][middle_pos.col]:
            self.board[middle_pos.row][middle_pos.col] = None

    def king_piece(self, pos: PiecePosition):
        piece = self.board[pos.row][pos.col]
        if piece and (pos.row == 0 or pos.row == 7):
            piece.is_king = True
```

