"""
This module contains the GameController class to orchestrate the game flow.
"""

from board import Board, PiecePosition
from move_validator import MoveValidator

class GameController:
    def __init__(self):
        self.board = Board()
        self.player_turn = Player('red')
        self.move_validator = MoveValidator(self.board)

    def handle_move(self, from_pos: str, to_pos: str):
        try:
            from_row, from_col = map(int, from_pos.split(','))
            to_row, to_col = map(int, to_pos.split(','))
            from_pos = PiecePosition(from_row - 1, from_col - 1)
            to_pos = PiecePosition(to_row - 1, to_col - 1)

            if self.move_validator.is_valid_move(from_pos, to_pos):
                self.board.move_piece(from_pos, to_pos)
                # Add capture and kinging logic here
                print("Move successful!")
            else:
                print("Invalid move!")

        except ValueError as e:
            print(f"Error parsing input: {e}")

    def switch_turn(self):
        if self.player_turn == Player('red'):
            self.player_turn = Player('black')
        else:
            self.player_turn = Player('red')

# This is the main module to launch the program
from game_controller import GameController

def run():
    controller = GameController()
    while True:
        current_player = controller.player_turn
        input_pos = input(f"{current_player} enter move (e.g., 1,2 3,4): ")
        if input_pos.lower() == 'q':
            break
        controller.handle_move(input_pos.split()[0], input_pos.split()[1])
        controller.switch_turn()

if __name__ == "__main__":
    run()
